// Sadə tip təsdiqi
let value: any = 'Hello';
let strLength: number = (value as string).length;
// və ya
let strLength2: number = (<string>value).length;

console.log(strLength); // 5
console.log(strLength2); // 5

// DOM ilə tip təsdiqi
let input = document.getElementById('myInput') as HTMLInputElement;
console.log(input.value); // input.value-ə təhlükəsiz müraciət

// Tip təsdiqi olmadan
let input2 = document.getElementById('myInput');
// console.log(input2.value); // Xəta: value xüsusiyyəti HTMLElement tipində yoxdur

// Birlik tipləri ilə tip təsdiqi
function processValue(value: string | number) {
  let result: string;
  if (typeof value === 'string') {
    result = value; // Avtomatik tip daraltması
  } else {
    result = (value as number).toFixed(2);
  }
  console.log(result);
}

processValue('Hello'); // Hello
processValue(42); // 42.00

// unknown ilə tip təsdiqi
function processUnknown(value: unknown) {
  if (typeof value === 'string') {
    console.log((value as string).toUpperCase());
  } else if (typeof value === 'number') {
    console.log((value as number).toFixed(2));
  } else {
    console.log('Unknown type');
  }
}

processUnknown('Hello'); // HELLO
processUnknown(42); // 42.00
processUnknown(true); // Unknown type

// Tip təsdiqi vs tip qoruyucusu
function unsafeAssert(value: any) {
  console.log((value as string).toUpperCase()); // Riskli: value string olmaya bilər
}

function safeGuard(value: any) {
  if (typeof value === 'string') {
    console.log(value.toUpperCase());
  } else {
    console.log('Not a string');
  }
}

unsafeAssert('Hello'); // HELLO
// unsafeAssert(42); // Runtime səhvi: toUpperCase metoduna malik deyil
safeGuard('Hello'); // HELLO
safeGuard(42); // Not a string

// Obyektlərdə tip təsdiqi
interface User {
  name: string;
}

let data: any = { name: 'Alice' };
let user = data as User;
console.log(user.name); // Alice

// Təhlükəsizlik nümunəsi
function processData(data: unknown) {
  if (typeof data === 'string') {
    return (data as string).toUpperCase();
  }
  return 'Unknown';
}

console.log(processData('Hello')); // HELLO
console.log(processData(42)); // Unknown

// Səhvə yol açan nümunə
function riskyAssert(value: any) {
  return (value as string).toUpperCase(); // Riskli: value string olmaya bilər
}

// Düzgün yol
function safeProcess(value: any) {
  if (typeof value === 'string') {
    return value.toUpperCase();
  }
  return 'Not a string';
}

console.log(riskyAssert('Hello')); // HELLO
// console.log(riskyAssert(42)); // Runtime səhvi: toUpperCase metoduna malik deyil
console.log(safeProcess('Hello')); // HELLO
console.log(safeProcess(42)); // Not a string

// Real layihə ssenarisi
interface Product {
  id: number;
  name: string;
}

function fetchProduct(data: any) {
  let product = data as Product;
  console.log(`Product: ${product.name}, ID: ${product.id}`);
}

fetchProduct({ id: 1, name: 'Laptop' }); // Product: Laptop, ID: 1

