    console.log((value as number).toFixed(2));
  } else {
    console.log('Unknown type');
  }
}

processUnknown('Hello'); // HELLO
processUnknown(42); // 42.00
processUnknown(true); // Unknown type

// Type assertion vs. type guard
function unsafeAssert(value: any) {
  console.log((value as string).toUpperCase()); // Risky: value may not be a string
}

function safeGuard(value: any) {
  if (typeof value === 'string') {
    console.log(value.toUpperCase());
  } else {
    console.log('Not a string');
  }
}

unsafeAssert('Hello'); // HELLO
